            success: function (data) {

                popUpNotification.show(kendo.toString(""تمت الإضافة بنجاح""), ""info"");
                $(""#ServiceNumber"").val("""");

            },
            error: function (xhr, status, error) {

                popUpNotification.show(kendo.toString(xhr.responseText), ""error"");



            }



        });

    });

</script>");
